const staticData = $getWorkflowStaticData('global');
const msg = ($input.first().json.message?.text || '').trim();
const chatId = $input.first().json.message?.chat?.id || '';

staticData.chatId = String(chatId);

// Parse: /search CompanyName [Days]
const match = msg.match(/^\/search\s+(.+?)(?:\s+(\d+))?\s*$/);

if (!match) {
  staticData.parseError = true;
  staticData.companyQuery = '';
  staticData.days = 0;
  return [{json: {
    parseError: true,
    chatId: String(chatId),
    errorMessage: "Invalid command format. Use: /search CompanyName [Days]\nExamples:\n  /search Oracle 30\n  /search Google"
  }}];
}

const companyQuery = match[1].trim();
let days = match[2] ? parseInt(match[2]) : 7;
// Clamp to 1-90
days = Math.max(1, Math.min(90, days));
const seconds = days * 86400;

staticData.parseError = false;
staticData.companyQuery = companyQuery;
staticData.days = days;
staticData.timeWindowSeconds = seconds;

console.log(`Search command: company='${companyQuery}', days=${days} (${seconds}s)`);

return [{json: {
  parseError: false,
  companyQuery: companyQuery,
  days: days,
  seconds: seconds,
  chatId: String(chatId)
}}];

const staticData = $getWorkflowStaticData('global');
const config = $input.all().map(i => i.json);
const query = (staticData.companyQuery || '').toLowerCase();

// If parse error, pass through with no matches
if (staticData.parseError) {
  staticData.matchedCompanies = [];
  return [{json: {found: false, reason: 'parse_error'}}];
}

// Case-insensitive partial match against company names
const matches = config.filter(c => {
  const isActive = String(c.Active).toUpperCase() === 'TRUE' || c.Active === true;
  if (!isActive) return false;
  const name = (c.Company || '').toLowerCase();
  return name.includes(query);
});

staticData.matchedCompanies = matches;

if (matches.length === 0) {
  console.log(`No company found matching '${query}' in config`);
  return [{json: {found: false, query: query, matchCount: 0}}];
}

const names = matches.map(m => m.Company).join(', ');
console.log(`Found ${matches.length} match(es) for '${query}': ${names}`);

return [{json: {
  found: true,
  query: query,
  matchCount: matches.length,
  matchedNames: names,
  matches: matches.map(m => ({company: m.Company, companyId: m.CompanyID, bucket: String(m.Bucket)}))
}}];

const staticData = $getWorkflowStaticData('global');
const matches = staticData.matchedCompanies || [];
const seconds = staticData.timeWindowSeconds || 604800; // default 7 days

const LOCATION = 'India';
const GEO_ID = '102713980';
const LOCATION_FILTER = '105214831'; // Bengaluru

// Bucket keyword templates (same as main workflow)
const bucketKeywords = {
  '1': '"software development engineer" OR "SDE" OR "SDE II" OR "SDE 2" OR "SDE-II" OR "software engineer II" OR "software engineer 2" OR "software engineer - II"',
  '2': '"software engineer III" OR "software engineer 3" OR "software developer 3"',
  '3': '"software engineer" OR "software developer" OR "backend engineer" OR "SDE" OR "MTS" OR "member of technical staff"',
  '4': '"software engineer" OR "software developer" OR "backend engineer" OR "SDE" OR "MTS" OR "member of technical staff"'
};

// Group matched companies by bucket
const buckets = {};
for (const m of matches) {
  const bucket = String(m.Bucket);
  if (!buckets[bucket]) buckets[bucket] = [];
  buckets[bucket].push(String(m.CompanyID));
}

// Build one URL per bucket
const urls = [];
for (const [bucket, companyIds] of Object.entries(buckets)) {
  const keywords = bucketKeywords[bucket];
  if (!keywords || companyIds.length === 0) continue;

  const encodedKeywords = encodeURIComponent(keywords);
  const companyFilter = companyIds.join(',');
  const encodedLocation = encodeURIComponent(LOCATION);

  const url = `https://www.linkedin.com/jobs/search/?keywords=${encodedKeywords}&f_C=${companyFilter}&f_TPR=r${seconds}&location=${encodedLocation}&geoId=${GEO_ID}&f_PP=${LOCATION_FILTER}&sortBy=DD`;

  urls.push({
    url: url,
    bucket: bucket,
    companyCount: companyIds.length
  });
}

// Initialize accumulator
staticData.foundJobLinks = [];

console.log(`Built ${urls.length} search URL(s) for ${matches.length} matched company/companies`);

if (urls.length === 0) {
  return [{json: {url: '', bucket: '0', companyCount: 0, noUrls: true}}];
}

return urls.map(u => ({json: u}));

const staticData = $getWorkflowStaticData('global');
const foundLinks = staticData.foundJobLinks || [];

const currentBucket = $('Loop Over URLs').first().json.bucket || '0';

const data = $input.first().json;
const links = data.links || [];
const titles = data.titles || [];
const companies = data.companies || [];
const locations = data.locations || [];

// ============================================================
// NEGATIVE TITLE FILTER (same as main workflow)
// ============================================================
const negativeBase = /\b(staff|principal|lead|manager|director|ios|android|machine.?learning|data.?scien|QA|SDET|devops|SRE|site.?reliability|frontend|front.?end|intern|test.?engineer|test.?auto|platform.?engineer|infra.?engineer|cloud.?engineer|security|mobile|embedded)\b/i;
const negativeSenior = /\b(senior|sr\.?)\b/i;
// ============================================================

let filtered = 0;
let duped = 0;
let added = 0;

for (let i = 0; i < links.length; i++) {
  const url = links[i] || '';
  const title = (titles[i] || '').trim();
  const company = (companies[i] || '').trim();
  const location = (locations[i] || '').trim();

  // Extract job ID
  const match = url.match(/-(\d{8,})(?:\?|$)/);
  const jobId = match ? match[1] : null;
  if (!jobId) continue;

  // Dedup within this run only (no sheet dedup)
  const alreadyFound = foundLinks.some(l => l.jobId === jobId);
  if (alreadyFound) { duped++; continue; }

  // Apply negative title filter
  if (negativeBase.test(title)) { filtered++; continue; }

  // For Bucket 1 & 2, also exclude 'senior'
  if ((currentBucket === '1' || currentBucket === '2') && negativeSenior.test(title)) {
    filtered++; continue;
  }

  foundLinks.push({
    url: `https://www.linkedin.com/jobs/view/${jobId}`,
    jobId: jobId,
    bucket: currentBucket,
    searchTitle: title,
    searchCompany: company,
    searchLocation: location
  });
  added++;
}

staticData.foundJobLinks = foundLinks;

console.log(`Bucket ${currentBucket}: ${links.length} total, ${added} new, ${duped} dupes, ${filtered} filtered`);

return [{json: {processed: true, bucket: currentBucket, total: links.length, added: added, duped: duped, filtered: filtered}}];

const staticData = $getWorkflowStaticData('global');
const foundLinks = staticData.foundJobLinks || [];

console.log(`Total job links found: ${foundLinks.length}`);

if (foundLinks.length === 0) {
  return [{json: {hasLinks: false, count: 0}}];
}

// Clear accumulator and initialize processed jobs array
staticData.foundJobLinks = [];
staticData.processedJobs = [];

// Fan out individual links — first item carries hasLinks flag for the IF node
return foundLinks.map((link, i) => ({json: {...link, hasLinks: true, count: foundLinks.length}}));

// ============================================================
// SETTINGS — same threshold as main workflow
// ============================================================
const MAX_EXPERIENCE_YEARS = 4; // Skip roles where minimum experience > 4 years
// ============================================================

const staticData = $getWorkflowStaticData('global');
const parsed = $input.first().json;

// Get search data from the loop item
let searchData = {};
try {
  searchData = $('Loop Over Jobs').first().json || {};
} catch(e) {
  searchData = {};
}

const jobId = searchData.jobId || '';
const bucket = searchData.bucket || '';
const searchTitle = searchData.searchTitle || '';
const searchCompany = searchData.searchCompany || '';

const title = (parsed.title || searchTitle || '').trim();
const company = (parsed.company || searchCompany || '').trim();
const location = (parsed.location || searchData.searchLocation || '').trim();
const description = (parsed.description || '').replace(/\s+/g, ' ').trim();
const criteria = parsed.criteria || [];

// Experience extraction (same regex patterns as main workflow)
let expText = 'Not specified';
let minExp = null;
let maxExp = null;

const descLower = description.toLowerCase();
const expPatterns = [
  /(\d+)\s*\+\s*(?:years|yrs)/i,
  /(\d+)\s*[-\u2013to]+\s*(\d+)\s*(?:years|yrs)/i,
  /(?:minimum|at least|min\.?)\s*(\d+)\s*(?:years|yrs)/i,
  /(\d+)\s*(?:years|yrs)\s*(?:of)?\s*(?:experience|exp)/i
];

for (const pattern of expPatterns) {
  const match = descLower.match(pattern);
  if (match) {
    minExp = parseInt(match[1]);
    maxExp = match[2] ? parseInt(match[2]) : null;
    expText = match[0].trim();
    break;
  }
}

for (const c of criteria) {
  const cLower = (c || '').toLowerCase().trim();
  if (cLower.includes('entry')) {
    if (!minExp) { minExp = 0; expText = cLower; }
  } else if (cLower.includes('mid-senior')) {
    if (!minExp) { minExp = 3; expText = cLower; }
  }
}

// ============================================================
// FILTER: Skip if experience requirement > threshold
// ============================================================
const skipDueToExp = minExp !== null && minExp > MAX_EXPERIENCE_YEARS;

if (skipDueToExp) {
  console.log(`Skipping ${title} at ${company}: requires ${expText} (min ${minExp} yrs > ${MAX_EXPERIENCE_YEARS})`);
  return [{json: {processed: true, skipped: true, title: title, company: company, reason: 'experience_too_high'}}];
}

// Format experience display
let expDisplay = 'Not specified';
if (minExp !== null && maxExp !== null) {
  expDisplay = `${minExp}-${maxExp} yrs`;
} else if (minExp !== null) {
  expDisplay = `${minExp}+ yrs`;
}

// Primary tag (same logic as main workflow)
let primaryTag = 'Generic';
const titleLower = title.toLowerCase();
if (/sde.?(?:ii|2)/i.test(titleLower)) primaryTag = 'SDE-II';
else if (/software.*engineer.*(?:iii|3)/i.test(titleLower)) primaryTag = 'SE-III';
else if (/mts|member.*technical/i.test(titleLower)) primaryTag = 'MTS';
else if (/senior|sr/i.test(titleLower)) primaryTag = 'Senior';
else if (/backend|back.?end/i.test(titleLower)) primaryTag = 'Backend';
else primaryTag = 'Generic';

// Accumulate processed jobs in static data (only valid ones reach here)
if (!staticData.processedJobs) staticData.processedJobs = [];
staticData.processedJobs.push({
  jobId: jobId,
  title: title,
  company: company,
  location: location,
  link: `https://www.linkedin.com/jobs/view/${jobId}`,
  expDisplay: expDisplay,
  primaryTag: primaryTag
});

console.log(`Processed: ${title} at ${company} (${expDisplay}) [${primaryTag}]`);

return [{json: {processed: true, skipped: false, title: title, company: company, expDisplay: expDisplay}}];

const staticData = $getWorkflowStaticData('global');
const jobs = staticData.processedJobs || [];
const days = staticData.days || 7;
const matchedNames = $('Lookup Company').first().json.matchedNames || 'Unknown';

// Build message
const MAX_LEN = 4000;
const messages = [];

const header = `\uD83D\uDD0D Jobs at ${matchedNames} (last ${days} days)\n\nFound ${jobs.length} opening${jobs.length !== 1 ? 's' : ''} in Bengaluru:\n\n`;

const entries = [];
for (let i = 0; i < jobs.length; i++) {
  const j = jobs[i];
  const num = i + 1;
  const exp = j.expDisplay && j.expDisplay !== 'Not specified' ? ` (${j.expDisplay})` : '';
  const tag = j.primaryTag ? ` [${j.primaryTag}]` : '';
  let entry = `${num}. ${j.company} \u2014 ${j.title}${exp}${tag}\n`;
  entry += `   \uD83D\uDCCD ${j.location || 'N/A'}\n`;
  entry += `   ${j.link}`;
  entries.push(entry);
}

let current = header;
for (const entry of entries) {
  if (current.length + entry.length + 2 > MAX_LEN) {
    messages.push(current.trim());
    current = '...contd\n\n';
  }
  current += entry + '\n\n';
}
if (current.trim()) messages.push(current.trim());

// Clean up static data
delete staticData.processedJobs;

console.log(`Formatted ${jobs.length} jobs into ${messages.length} message(s)`);

return [{json: {messages: messages, count: jobs.length}}];

const data = $input.first().json;
const messages = data.messages || [];

return messages.map(msg => ({
  json: { message: msg }
}));
